function editTrip(id){const t=state.trips.find(x=>x.id===id);if(!t)return;setScreen('log');document.querySelector('[data-tab="trip"]').click();tripEditId.value=t.id;tripFormTitle.textContent='Edit trip';tripDate.value=t.date;tripVehicle.value=t.vehicleId||'';fillLocations();tripFrom.value=t.from||'home1';tripTo.value=t.to||'work';tripKm.value=t.km||0;tripPurpose.value=t.purpose||'Commute';tripNotes.value=t.notes||'';pendingAttachment.trip=t.attachment||null;showAttachment('trip');cancelTripEdit.classList.remove('hidden');window.scrollTo({top:0,behavior:'smooth'})}
