async function fileData(file){if(!file)return null;if(file.size>4_000_000)throw new Error('File too large');return new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res({name:file.name,type:file.type,data:r.result,date:new Date().toISOString()});r.onerror=rej;r.readAsDataURL(file)})}
