function vehicleDistance(v){return state.trips.filter(t=>t.vehicleId===v.id).reduce((sum,t)=>sum+Number(t.km||0),0)}
function maintenanceTimeline(v){
  const current=Math.max(vehicleDistance(v),...state.expenses.filter(e=>e.vehicleId===v.id).map(e=>Number(e.odometer||0)),0);
  const maintenance=state.expenses.filter(e=>e.vehicleId===v.id&&e.category==='Maintenance'&&Number(e.odometer||0)>0).sort((a,b)=>a.odometer-b.odometer);
  const last=maintenance.at(-1);const interval=Number(v.maintenanceKm||0);const due=interval?(Number(last?.odometer||0)+interval):0;
  const max=Math.max(current,due,1);const p=n=>Math.min(100,Math.max(0,(Number(n||0)/max)*100));
  return `<div class="maintenance-timeline"><div class="timeline-track"></div><span class="timeline-point start" style="left:0%"><b>0</b></span>${maintenance.map(m=>`<span class="timeline-point maintenance" style="left:${p(m.odometer)}%" title="Maintenance ${m.date}"><b>${Number(m.odometer).toFixed(0)} km</b><i>●</i></span>`).join('')}<span class="timeline-point current" style="left:${p(current)}%"><b>${current.toFixed(0)} km current</b><i>●</i></span>${due>current?`<span class="timeline-point due" style="left:${p(due)}%"><b>${due.toFixed(0)} km maintenance</b><i>●</i></span>`:''}</div>`
}
function renderGarage(){const typeFilter=document.getElementById('garageTypeFilter')?.value||'all',powerFilter=document.getElementById('garagePowertrainFilter')?.value||'all';const list=state.vehicles.filter(v=>(typeFilter==='all'||v.type===typeFilter)&&(powerFilter==='all'||(v.powertrain||'not_applicable')===powerFilter));if(!list.length){garageList.innerHTML='<div class="card empty-state">No matching vehicles.</div>';return}garageList.innerHTML=list.map(v=>{const trips=state.trips.filter(t=>t.vehicleId===v.id),logs=state.expenses.filter(e=>e.vehicleId===v.id);const title=[v.brand,v.model].filter(Boolean).join(' ')||v.name;return `<div class="card garage-card"><div class="section-head"><div class="vehicle-title"><span class="vehicle-icon">${iconType(v.type)}</span><div><h3>${title}</h3><strong>${v.name}</strong><p class="muted">${String(v.type).replaceAll('_',' ')} · ${String(v.powertrain||'not_applicable').replaceAll('_',' ')}</p>${v.isDefault?'<span class="default-badge">DEFAULT</span>':''}</div></div><div class="log-actions"><button class="ghost" data-edit-vehicle="${v.id}">Edit</button><button class="ghost" data-archive-vehicle="${v.id}">${v.active===false?'Restore':'Archive'}</button></div></div><div class="vehicle-meta"><div><small>Distance logged</small>${unitDistance(trips.reduce((s,t)=>s+Number(t.km||0),0))}</div><div><small>Tickets & logs</small>${logs.length}</div><div><small>Total cost</small>${money(logs.reduce((s,e)=>s+Number(e.amount||0),0))}</div><div><small>Status</small>${v.active===false?'Archived':'Active'}</div></div>${['bicycle','ebike','speed_pedelec','car','van','motorcycle','scooter'].includes(v.type)?maintenanceTimeline(v):''}${v.leasePartner?`<p>Lease partner: ${link(v.leasePartner,v.leaseUrl)}</p>`:''}${v.maintenanceProvider?`<p>Maintenance: ${link(v.maintenanceProvider,v.maintenanceUrl)}</p>`:''}${v.insurance?`<p>Insurance: ${v.insurance}</p>`:''}<button class="secondary small" data-vehicle-logs="${v.id}">See all logs for this vehicle</button></div>`}).join('');document.querySelectorAll('[data-edit-vehicle]').forEach(b=>b.onclick=()=>openVehicle(null,b.dataset.editVehicle));document.querySelectorAll('[data-archive-vehicle]').forEach(b=>b.onclick=()=>archiveVehicle(b.dataset.archiveVehicle));document.querySelectorAll('[data-vehicle-logs]').forEach(b=>b.onclick=()=>showVehicleLogs(b.dataset.vehicleLogs))}
function link(label,url){return url?`<a href="${url}" target="_blank" rel="noopener">${label}</a>`:label}

