function archiveVehicle(id){const v=vehicleById(id);if(!v)return;if(v.isDefault&&v.active!==false&&!confirm('This is the default vehicle. Archive it and choose a new default later?'))return;v.active=v.active===false;save();renderGarage()}
function showVehicleLogs(id){selectedDay=todayISO();setScreen('calendar');const rows=allRows().filter(x=>x.vehicleId===id);selectedDayTitle.textContent=`Logs for ${vehicleById(id)?.name||'vehicle'}`;dayLogs.innerHTML=rows.length?rows.map(logHtml).join(''):'No logs.';bindLogButtons(dayLogs)}
function renderStats(){
  const totalKm=state.trips.reduce((s,t)=>s+Number(t.km||0),0);
  const totalCost=state.expenses.reduce((s,e)=>s+Number(e.amount||0),0);
  const receipts=state.expenses.filter(e=>e.attachment).length;
  const byVehicle=state.vehicles.map(v=>({
    v,
    km:state.trips.filter(t=>t.vehicleId===v.id).reduce((s,t)=>s+Number(t.km||0),0)
  })).filter(x=>x.km>0).sort((a,b)=>b.km-a.km);

  const palette=['#ff9d1c','#ffc14d','#f07818','#d9a441','#f4f4f4','#9b9b9f','#6f7075','#45464b'];
  let cursor=0;
  const gradientParts=byVehicle.map((x,i)=>{
    const percentage=totalKm?x.km/totalKm*100:0;
    const from=cursor;
    cursor+=percentage;
    return `${palette[i%palette.length]} ${from.toFixed(2)}% ${cursor.toFixed(2)}%`;
  });
  const usageChart=byVehicle.length?`<div class="usage-mix-layout"><div class="usage-donut" role="img" aria-label="Share of logged distance by vehicle" style="--usage-gradient:conic-gradient(${gradientParts.join(',')})"><div><strong>${byVehicle.length}</strong><span>vehicles</span></div></div><div class="usage-legend">${byVehicle.map((x,i)=>{const percentage=totalKm?x.km/totalKm*100:0;return `<div class="usage-legend-row"><span class="usage-dot" style="background:${palette[i%palette.length]}"></span><span class="usage-name">${escapeHtml(x.v.name)}</span><strong>${percentage.toFixed(1)}%</strong></div>`}).join('')}</div></div>`:'<p class="muted">Log trips with Garage vehicles to see your mobility mix.</p>';

  const cyclingTypes=['bicycle','ebike','speed_pedelec'];
  const cyclingKm=state.trips.filter(t=>cyclingTypes.includes(vehicleById(t.vehicleId)?.type)).reduce((s,t)=>s+Number(t.km||0),0);
  const estimatedCo2Saved=cyclingKm*0.17;

  statsContent.innerHTML=`
    <div class="card usage-mix-card">
      <div class="section-head"><div><h3>Vehicle usage mix</h3><p class="muted">Share of your logged distance</p></div></div>
      ${usageChart}
    </div>
    <div class="stats-kpi-grid">
      <div class="card stat-summary-row"><span>Total trips</span><strong>${state.trips.length}</strong></div>
      <div class="card stat-summary-row"><span>Total distance</span><strong>${unitDistance(totalKm)}</strong></div>
      <div class="card stat-summary-row"><span>Total costs</span><strong>${money(totalCost)}</strong></div>
      <div class="card stat-summary-row"><span>Receipts</span><strong>${receipts}</strong></div>
    </div>
    <div class="card">
      <h3>Distance per vehicle</h3>
      <div class="vehicle-distance-list">${byVehicle.map(x=>`<div class="vehicle-distance-row"><span class="vehicle-distance-icon">${iconType(x.v.type)}</span><span class="vehicle-distance-name">${escapeHtml(x.v.name)}</span><strong>${unitDistance(x.km)}</strong></div>`).join('')||'<p class="muted">No distance yet.</p>'}</div>
    </div>
    <div class="card impact-card">
      <h3>Estimated impact</h3>
      <div class="impact-row"><span>Cycling distance</span><strong>${unitDistance(cyclingKm)}</strong></div>
      <div class="impact-row"><span>Estimated CO₂ avoided</span><strong>${estimatedCo2Saved.toFixed(1)} kg</strong></div>
      <p class="muted">Estimated against an avoided average car journey. Actual savings vary by vehicle, energy source and route.</p>
    </div>`;
}
function renderCalendar(){calendarTitle.textContent=fmtMonth(calendarDate);const y=calendarDate.getFullYear(),m=calendarDate.getMonth(),first=(new Date(y,m,1).getDay()+6)%7,days=new Date(y,m+1,0).getDate(),counts={};allRows().forEach(x=>counts[x.date]=(counts[x.date]||0)+1);let html='';for(let i=0;i<first;i++)html+='<span></span>';for(let d=1;d<=days;d++){const iso=`${y}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;html+=`<button class="cal-day ${counts[iso]?'filled':''} ${iso===selectedDay?'selected':''} ${iso===todayISO()?'today':''}" data-day="${iso}"><span>${d}</span>${counts[iso]?`<small>${counts[iso]}</small>`:''}</button>`}calendarGrid.innerHTML=html;document.querySelectorAll('[data-day]').forEach(b=>b.onclick=()=>{selectedDay=b.dataset.day;renderCalendar()});selectedDayTitle.textContent=new Date(selectedDay+'T12:00:00').toLocaleDateString(undefined,{weekday:'long',day:'numeric',month:'long'});const rows=allRows().filter(x=>x.date===selectedDay);dayLogs.innerHTML=rows.length?rows.map(logHtml).join(''):'No registrations on this day.';bindLogButtons(dayLogs)}
function renderSettings(){settingName.value=state.settings.name||'';settingLanguage.value=state.settings.language||window.MOBUD_I18N?.language||'en';settingCurrency.value=state.settings.currency||'€';settingUnit.value=state.settings.unit||'km';settingTheme.value=state.settings.theme||'system';commuteReminderMode.value=state.settings.commuteReminderMode||'never';dailyReminderTime.value=state.settings.dailyReminderTime||'19:00';weeklyReminderDay.value=String(state.settings.weeklyReminderDay??6);weeklyReminderTime.value=state.settings.weeklyReminderTime||'10:00';backupFrequency.value=state.settings.backupFrequency||'never';reportFrequency.value=state.settings.reportFrequency||'never';notifyUpdates.checked=!!state.settings.notifyUpdates;storageStatus.textContent=state.settings.driveConnected?`Google Drive connected · last sync ${state.settings.lastDriveSync||'never'}`:'Data is stored locally on this device.';linkDrive.classList.toggle('hidden',state.settings.driveConnected);syncDrive.classList.toggle('hidden',!state.settings.driveConnected);disconnectDrive.classList.toggle('hidden',!state.settings.driveConnected);addressFields.innerHTML=['home1','home2','home3','work'].map(k=>`<label>${({home1:'Home 1',home2:'Home 2',home3:'Home 3',work:'Work'})[k]}<input data-address="${k}" value="${state.settings[k]||''}" placeholder="Enter and select an address"><div class="suggestions" id="suggest_${k}"></div></label>`).join('');document.querySelectorAll('[data-address]').forEach(inp=>{let timer;inp.oninput=()=>{clearTimeout(timer);timer=setTimeout(()=>searchAddress(inp.dataset.address,inp.value),450)}});renderFaq()}
async function searchAddress(key,text){const box=document.getElementById('suggest_'+key);if(text.trim().length<3){box.innerHTML='';return}try{const r=await fetch(`${API}/geocode?text=${encodeURIComponent(text)}`,{cache:'no-store'});if(!r.ok)throw new Error(r.status);const j=await r.json();box.innerHTML=(j.features||[]).slice(0,5).map((f,i)=>`<button type="button" class="ghost small" data-suggestion="${key}" data-index="${i}">${f.properties.label}</button>`).join('');box._features=j.features||[];box.querySelectorAll('[data-suggestion]').forEach(b=>b.onclick=()=>{const f=box._features[Number(b.dataset.index)];state.settings[key]=f.properties.label;state.addresses[key]={label:f.properties.label,coords:f.geometry.coordinates};save()})}catch(e){box.innerHTML='<small class="muted">Address search unavailable; manual entry remains possible.</small>'}}
function profile(type){return ['bicycle','ebike','speed_pedelec'].includes(type)?'cycling-regular':type==='walking'?'foot-walking':'driving-car'}
async function routeDistance(a,b,type){const cacheKey=[profile(type),...a,...b].join('|');if(state.routeCache[cacheKey])return state.routeCache[cacheKey];const r=await fetch(`${API}/route`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({profile:profile(type),coordinates:[a,b]})});if(!r.ok)throw new Error(r.status);const j=await r.json();const km=j.features?.[0]?.properties?.summary?.distance/1000;if(!km)throw new Error('No route');state.routeCache[cacheKey]=km;save();return km}
function renderFaq(){const items=[['How do I add a vehicle?','Open Garage and tap Add vehicle. The first vehicle of a type becomes the default.','garage'],['How do I attach a ticket or bill?','Open Log, choose Trip or Cost, then Choose file or Take photo. Keep the original document.','log'],['Can I discard the original receipt?','No. Keep the legally valid paper or native electronic original for the applicable retention period. MoBud copies are administrative aids only.'],['Where is my data stored?','Locally by default. Optional Google Drive backup remains in your own Google account. MoBud does not operate a central trip database.'],['How do I use multiple devices?','Link the same Google Drive account on each device, then restore or sync the same backup.'],['How do commute reminders work?','Choose daily or weekly in Setup. The beta checks reminders whenever MoBud is open; reliable closed-app notifications require the future push service.'],['Does MoBud determine tax deductibility?','No. Consult your accountant or tax adviser. MoBud only organises records and estimates.']];faqList.innerHTML=items.map((x,i)=>`<div class="faq-item"><button data-faq="${i}">${x[0]}</button><div class="faq-answer hidden" id="faq_${i}">${x[1]} ${x[2]?`<button class="ghost small" data-tutorial-start="${x[2]}">Show tutorial</button>`:''}</div></div>`).join('');document.querySelectorAll('[data-faq]').forEach(b=>b.onclick=()=>document.getElementById('faq_'+b.dataset.faq).classList.toggle('hidden'));document.querySelectorAll('[data-tutorial-start]').forEach(b=>b.onclick=()=>startTutorial(b.dataset.tutorialStart))}
