function startTutorial(id){tutorialIndex=Math.max(0,tutorialSteps.findIndex(s=>s.id===id||s.title.toLowerCase().includes(String(id||'').toLowerCase())));tutorial.classList.remove('hidden');showTutorial()}
const waitForElement=(selector,timeout=1600)=>new Promise(resolve=>{const start=performance.now();(function tick(){const el=document.querySelector(selector);if(el)return resolve(el);if(performance.now()-start>timeout)return resolve(null);requestAnimationFrame(tick)})()});
async function showTutorial(){const step=tutorialSteps[tutorialIndex];tutorialCount.textContent=`${tutorialIndex+1} / ${tutorialSteps.length}`;tutorialTitle.textContent=step.title;tutorialText.textContent=step.text;tutorialNext.textContent=tutorialIndex===tutorialSteps.length-1?'Have fun':'Next';setScreen(step.screen);step.action?.();const el=await waitForElement(step.target);if(!el){tutorialIndex++;if(tutorialIndex<tutorialSteps.length)return showTutorial();tutorial.classList.add('hidden');return}el.scrollIntoView({behavior:'smooth',block:'center',inline:'center'});await new Promise(r=>setTimeout(r,360));requestAnimationFrame(()=>requestAnimationFrame(()=>positionTutorial(el)))}
function positionTutorial(el){const r=el.getBoundingClientRect(),pad=7;const left=Math.max(6,r.left-pad),top=Math.max(6,r.top-pad),width=Math.min(innerWidth-left-6,r.width+pad*2),height=Math.min(innerHeight-top-6,r.height+pad*2);tutorialSpot.style.cssText=`left:${left}px;top:${top}px;width:${width}px;height:${height}px`}
window.addEventListener('resize',()=>{if(!tutorial.classList.contains('hidden')){const step=tutorialSteps[tutorialIndex],el=document.querySelector(step?.target);if(el)positionTutorial(el)}});
function finishOnboardingFlow(){state.onboardingComplete=true;state.settings.name=onboardName.value.trim();state.settings.language=onboardLanguage.value||window.MOBUD_I18N?.language||'en';window.MOBUD_I18N?.setLanguage?.(state.settings.language);state.settings.storageMode=document.querySelector('[name=storageChoice]:checked').value;state.settings.commuteReminderMode=onboardCommuteReminder.value;state.settings.dailyReminderTime='19:00';state.settings.weeklyReminderDay=6;state.settings.weeklyReminderTime='10:00';state.settings.backupFrequency=onboardBackup.value;state.settings.reportFrequency=onboardReport.value;state.settings.notifyUpdates=onboardNotify.checked;save();onboarding.classList.add('hidden');if(state.settings.storageMode==='drive')linkGoogleDrive();setTimeout(()=>{if(confirm('Want a quick MoBud tutorial?'))startTutorial()},200)}
const DRIVE_BACKUP_NAME='mobud-backup.json';
async function driveFetch(url,options={}){const token=sessionStorage.getItem('mobudGoogleToken');if(!token)throw new Error('NO_TOKEN');const headers=new Headers(options.headers||{});headers.set('Authorization',`Bearer ${token}`);const response=await fetch(url,{...options,headers});if(response.status===401)sessionStorage.removeItem('mobudGoogleToken');return response}
async function findDriveBackup(){const q=encodeURIComponent(`name='${DRIVE_BACKUP_NAME}' and 'appDataFolder' in parents and trashed=false`);const r=await driveFetch(`https://www.googleapis.com/drive/v3/files?spaces=appDataFolder&q=${q}&fields=files(id,name,modifiedTime)&pageSize=10`);if(!r.ok)throw new Error(`Drive list failed (${r.status})`);const j=await r.json();return (j.files||[]).sort((a,b)=>String(b.modifiedTime).localeCompare(String(a.modifiedTime)))[0]||null}
async function downloadDriveBackup(fileId){const r=await driveFetch(`https://www.googleapis.com/drive/v3/files/${encodeURIComponent(fileId)}?alt=media`);if(!r.ok)throw new Error(`Drive download failed (${r.status})`);const data=normalized(await r.json());if(!validData(data))throw new Error('Invalid Drive backup');return data}
async function uploadDriveBackup(existingId=''){const metadata={name:DRIVE_BACKUP_NAME,mimeType:'application/json'};if(!existingId)metadata.parents=['appDataFolder'];const boundary='mobud_'+Math.random().toString(36).slice(2);const body=`--${boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n${JSON.stringify(metadata)}\r\n--${boundary}\r\nContent-Type: application/json\r\n\r\n${JSON.stringify(buildBackupPayload())}\r\n--${boundary}--`;const endpoint=existingId?`https://www.googleapis.com/upload/drive/v3/files/${encodeURIComponent(existingId)}?uploadType=multipart`:'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart';const r=await driveFetch(endpoint,{method:existingId?'PATCH':'POST',headers:{'Content-Type':`multipart/related; boundary=${boundary}`},body});if(!r.ok)throw new Error(`Drive upload failed (${r.status})`);return r.json()}
async function linkGoogleDrive(){if(!GOOGLE_CLIENT_ID){toast('Add the Google OAuth Client ID to config.js first.');return}if(!window.google?.accounts?.oauth2){toast('Google sign-in is not ready yet. Reload and try again.');return}const client=google.accounts.oauth2.initTokenClient({client_id:GOOGLE_CLIENT_ID,scope:'https://www.googleapis.com/auth/drive.appdata',callback:async token=>{if(token.error){toast('Google Drive connection was cancelled.');return}sessionStorage.setItem('mobudGoogleToken',token.access_token);state.settings.driveConnected=true;state.settings.storageMode='drive';save();await syncToDrive(true)}});client.requestAccessToken({prompt:'consent'})}
async function syncToDrive(firstConnection=false){const token=sessionStorage.getItem('mobudGoogleToken');if(!token){linkGoogleDrive();return}try{toast('Checking Google Drive…');const existing=await findDriveBackup();if(existing&&firstConnection){const restore=confirm('A MoBud backup already exists in this Google Drive. Press OK to restore it on this device. Press Cancel to keep this device and replace the Drive backup.');if(restore){const remote=await downloadDriveBackup(existing.id);snapshot(KEY,JSON.stringify(state),'before-drive-restore');state=remote;state.settings.driveConnected=true;state.settings.storageMode='drive';state.settings.lastDriveSync=new Date().toLocaleString();save();toast(`Drive backup restored · ${state.vehicles.length} vehicle(s)`);return}}await uploadDriveBackup(existing?.id||'');state.settings.lastDriveSync=new Date().toLocaleString();state.settings.driveConnected=true;state.settings.storageMode='drive';save();toast('Google Drive backup updated.')}catch(error){console.error(error);toast('Google Drive sync failed. Your local data was kept.')}}
function openFeedback(type){feedbackForm.reset();feedbackType.value=type;feedbackTitle.textContent=type==='bug'?'Report bug':'Send request';feedbackModal.classList.remove('hidden')}
function feedbackPayload(){return {type:feedbackType.value,title:feedbackSubject.value,description:feedbackDescription.value,severity:feedbackSeverity.value,email:feedbackEmail.value,mayContact:feedbackContact.checked,version:VERSION,platform:navigator.platform,installed:matchMedia('(display-mode: standalone)').matches,online:navigator.onLine}}

function reminderKeyForNow(){const n=new Date(),mode=state.settings.commuteReminderMode;if(mode==='daily'){const [h,m]=(state.settings.dailyReminderTime||'19:00').split(':').map(Number);if(n.getHours()>h||(n.getHours()===h&&n.getMinutes()>=m))return `daily-${todayISO()}`}if(mode==='weekly'&&n.getDay()===Number(state.settings.weeklyReminderDay??6)){const [h,m]=(state.settings.weeklyReminderTime||'10:00').split(':').map(Number);if(n.getHours()>h||(n.getHours()===h&&n.getMinutes()>=m))return `weekly-${todayISO()}`}return ''}
function checkCommuteReminder(){const key=reminderKeyForNow();if(!key||state.settings.lastCommuteReminder===key)return;state.settings.lastCommuteReminder=key;save();const msg=state.settings.commuteReminderMode==='weekly'?'Review and complete your commutes from the past week.':'Remember to log today’s commute.';toast(msg);if(Notification.permission==='granted')new Notification('MoBud reminder',{body:msg,icon:'icon-192-v005.png'})}
